  {"id":"avf-ceramics-010","type":"authentic_vs_fake","category":"ceramics","subject":"Porcelain Stone vs Pottery Clay Body Identification","authentic_markers":[{"feature":"Correct clay body for claimed ware type","detail":"Porcelain shows white, vitrified body; stoneware shows gray/brown body","detection_method":"Unglazed foot examination"},{"feature":"Translucency appropriate for porcelain claims","detail":"Thin porcelain transmits light; stoneware does not","detection_method":"Transmitted light test"}],"fake_markers":[{"feature":"Stoneware body on claimed porcelain piece","detail":"Opaque body despite porcelain attribution","common_in":"Mislabeled ceramics"},{"feature":"Modern high-alumina body","detail":"Too white, too uniform for traditional production","common_in":"Modern imitations"}],"confidence_notes":"The distinction between porcelain and stoneware is fundamental. Arita porcelain uses specific touseki (porcelain stone) identifiable through petrographic analysis","sources":["Kyushu Ceramic Museum technical studies"],"verified_by":"source_verified"},
  {"id":"avf-painting-007","type":"authentic_vs_fake","category":"painting","subject":"Gold Leaf (Kinpaku) Authentication in Screen Paintings","authentic_markers":[{"feature":"Hand-applied gold leaf with visible overlap seams","detail":"Slight irregularity at leaf boundaries","detection_method":"Raking light examination"},{"feature":"Period-appropriate gold purity","detail":"Traditional gold leaf uses high-purity gold with trace silver","detection_method":"XRF analysis"}],"fake_markers":[{"feature":"Gold-colored paint or metallic ink","detail":"Lacks the reflective quality and depth of real gold leaf","common_in":"Reproductions and tourist screens"},{"feature":"Machine-pressed gold leaf with perfect uniformity","detail":"No variation in thickness or overlap pattern","common_in":"Modern commercial production"}],"confidence_notes":"Gold leaf quality is a reliable indicator of production intent — ceremonial screens use the finest kinpaku, while commercial screens may use inferior substitutes","sources":["Tokyo National Museum gold leaf analysis","Kanazawa gold leaf production studies"],"verified_by":"source_verified"},
  {"id":"avf-textiles-006","type":"authentic_vs_fake","category":"textiles","subject":"Living National Treasure Textile Authentication","authentic_markers":[{"feature":"Documented in artist's production records","detail":"Each piece registered with serial number or documentation","detection_method":"Provenance verification"},{"feature":"Technique consistent with artist's designated skill","detail":"The specific intangible cultural property technique is evident","detection_method":"Expert textile analysis"}],"fake_markers":[{"feature":"Claims LNT designation without documentation","detail":"No registration, no certificate, no exhibition record","common_in":"Misattributed or upgraded textiles"},{"feature":"Technique quality below LNT standard","detail":"Shortcuts or simplifications inconsistent with master-level work","common_in":"Student or workshop pieces attributed to master"}],"confidence_notes":"Living National Treasure designation creates extreme price premiums, making misattribution profitable. Documentation verification is essential","sources":["Agency for Cultural Affairs LNT records"],"verified_by":"source_verified"},
  {"id":"avf-metalwork-007","type":"authentic_vs_fake","category":"metalwork","subject":"Meiji Export Metalwork — Quality Spectrum","authentic_markers":[{"feature":"Fine detail work consistent with exhibition-quality craft","detail":"Precise inlay, complex alloy work, signed by known craftsman","detection_method":"Visual examination, signature verification"},{"feature":"Weight and density consistent with genuine alloys","detail":"Proper shakudo, shibuichi, or bronze composition","detection_method":"XRF, weight assessment"}],"fake_markers":[{"feature":"Cast reproduction of hand-worked original","detail":"Loss of fine detail, casting mold lines visible","common_in":"Southeast Asian reproductions"},{"feature":"Electroplated base metal","detail":"Plating wear reveals different base material","common_in":"Modern commercial reproductions"}],"confidence_notes":"Meiji metalwork ranges from imperial exhibition masterpieces to mass-produced export ware. Quality assessment is critical for accurate valuation","sources":["Harris, Japanese Imperial Craftsmen"],"verified_by":"source_verified"},
